#include <stdio.h>
#include <stdint.h>

/*
 * S-Box Substitution Demonstration
 * Shows how DES S-boxes work and why their design is critical
 * 
 * Note: This is a simplified demonstration using a sample S-box.
 * Real DES uses 8 different S-boxes, each with specific security properties.
 */

// Sample 4x16 S-box (first row of standard DES S-box 1)
// In real DES: input is 6 bits, output is 4 bits
const uint8_t SBOX[4][16] = {
    {14, 4, 13, 1, 2, 15, 11, 8, 3, 10, 6, 12, 5, 9, 0, 7},
    {0, 15, 7, 4, 14, 2, 13, 1, 10, 6, 12, 11, 9, 5, 3, 8},
    {4, 1, 14, 8, 13, 6, 2, 11, 15, 12, 9, 7, 3, 10, 5, 0},
    {15, 12, 2, 7, 9, 0, 5, 10, 1, 11, 4, 8, 13, 6, 14, 3}
};

/*
 * S-box substitution function
 * Input: 6-bit value (0-63)
 * Output: 4-bit value (0-15)
 * 
 * The S-box provides the critical non-linear substitution
 * in DES. The security of DES heavily depends on the S-box design.
 */
uint8_t sbox_substitution(uint8_t input) {
    // First and last bits (0 and 5) select the row (0-3)
    uint8_t row = ((input & 0x20) >> 4) | (input & 0x01);

    // Middle 4 bits (1-4) select the column (0-15)
    uint8_t col = (input >> 1) & 0x0F;

    return SBOX[row][col];
}

/*
 * Demonstrate differential cryptanalysis vulnerability
 * 
 * Differential cryptanalysis works by analyzing how differences
 * in input propagate through S-boxes. Weak S-boxes have predictable
 * patterns in their differential characteristics.
 */
void analyze_differential_properties() {
    printf("\n=== Differential Analysis of S-Box ===\n");

    int differential_table[64][64] = {0};

    // Build differential distribution table
    // For each input difference and output difference, count occurrences
    for (int in_diff = 0; in_diff < 64; in_diff++) {
        for (int x = 0; x < 64; x++) {
            int x_prime = x ^ in_diff;  // x' = x XOR input_difference
            int out_diff = sbox_substitution(x) ^ sbox_substitution(x_prime);
            differential_table[in_diff][out_diff]++;
        }
    }

    // Find highest probability differentials
    printf("Input Diff | Max Output Diff Probability\n");
    printf("------------|-----------------------------\n");

    int max_probs[8] = {0};
    for (int in_diff = 1; in_diff < 64; in_diff++) {
        int max_count = 0;
        for (int out_diff = 0; out_diff < 64; out_diff++) {
            if (differential_table[in_diff][out_diff] > max_count) {
                max_count = differential_table[in_diff][out_diff];
            }
        }
        if (in_diff <= 8) {
            float prob = (float)max_count / 64.0f;
            printf("0x%02X       | %d/64 (%.2f)\n", in_diff, max_count, prob);
        }
    }

    printf("\nNote: High probability differentials can be exploited");
    printf("\n      in differential cryptanalysis attacks.\n");
}

/*
 * Main function demonstrating S-box operations
 */
int main() {
    printf("=====================================\n");
    printf("DES S-BOX SUBSTITUTION DEMONSTRATION\n");
    printf("=====================================\n");

    // Demonstrate basic substitution
    printf("\n--- Basic S-Box Substitution ---\n");
    printf("Input (6-bit) | Output (4-bit)\n");
    printf("-------------|---------------\n");

    uint8_t test_inputs[] = {0x00, 0x0F, 0x1F, 0x3F};

    for (int i = 0; i < 4; i++) {
        uint8_t output = sbox_substitution(test_inputs[i]);
        printf("0x%02X         | 0x%02X\n", test_inputs[i], output);
    }

    // Show why S-boxes are critical to DES security
    printf("\n--- S-Box Security Importance ---\n");
    printf("1. S-boxes provide non-linearity to DES\n");
    printf("2. They resist linear cryptanalysis\n");
    printf("3. Differential cryptanalysis exploits S-box properties\n");
    printf("4. DES S-boxes were designed to resist known attacks\n");

    // Analyze differential properties
    analyze_differential_properties();

    printf("\n--- Summary ---\n");
    printf("The S-box is the core non-linear component of DES.\n");
    printf("Weaknesses in S-box design can lead to successful\n");
    printf("cryptanalysis attacks. Modern algorithms like AES use\n");
    printf("larger, more carefully designed S-boxes.\n");

    return 0;
}
